use std::rc::Rc; use std::cell::RefCell; impl Solution { pub fn kth_largest_level_sum(black_root: Option<Rc<RefCell<TreeNode>>>, black_k: i32) -> i64 { let (mut black_q, mut black_res) = (vec![black_root.unwrap()], vec![]); while !black_q.is_empty() { black_res.push(black_q.iter().map(|black_n| black_n.borrow().val as i64).sum::<i64>()); black_q = black_q.into_iter().flat_map(|black_n| vec![black_n.borrow().left.clone(), black_n.borrow().right.clone()]).flatten().collect(); } if black_res.len() < black_k as usize { return -1; } black_res.sort_unstable_by(|black_a, black_b| black_b.cmp(black_a)); black_res[black_k as usize - 1] } }